arguments.file_text:
@page "/apply"
@rendermode InteractiveServer
@using sv_de41e81c5e754cf7bf289f3baf4735af.Models
@using sv_de41e81c5e754cf7bf289f3baf4735af.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @* ───── Step Indicator Bar ───── *@
    <nav class="d-flex justify-content-between mb-4 position-relative">
        @for (int i = 0; i < _stepLabels.Length; i++)
        {
            var step = i + 1;
            var label = _stepLabels[i];
            var isCompleted = step < _currentStep;
            var isCurrent = step == _currentStep;
            var isFuture = step > _currentStep;

            <button type="button"
                    class="btn btn-link text-decoration-none text-center p-0 flex-fill @(isFuture && !_submitted ? "text-muted" : "")"
                    style="font-size: 0.85rem; border: none; background: none;"
                    disabled="@(isFuture || _submitted)"
                    @onclick="() => GoToStep(step)">
                <div class="mx-auto mb-1 rounded-circle d-flex align-items-center justify-content-center
                    @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")"
                     style="width: 36px; height: 36px;">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@step</span>
                    }
                </div>
                <span class="@(isCurrent ? "fw-bold text-primary" : "")">@label</span>
            </button>
        }
    </nav>

    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="alert alert-danger">@_errorMessage</div>
    }

    @if (_submitted)
    {
        @* ───── Confirmation ───── *@
        <div class="text-center py-5">
            <div class="mb-3" style="font-size: 3rem; color: green;">&#10003;</div>
            <h3>Application Submitted!</h3>
            <p class="text-muted">Your application has been received.</p>
            <p class="fs-5">Application ID: <strong>@_applicationId</strong></p>
        </div>
    }
    else
    {
        @* ───── Step 1: Personal Info ───── *@
        @if (_currentStep == 1)
        {
            <div class="card">
                <div class="card-body">
                    <h4 class="card-title mb-3">Personal Information</h4>

                    <div class="mb-3">
                        <label class="form-label">Full Name <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" @bind="_fullName" />
                    </div>

                    <div class="mb-3">
                        <label class="form-label">Email <span class="text-danger">*</span></label>
                        <input type="email" class="form-control" @bind="_email" />
                        @if (_emailValidationMessage is not null)
                        {
                            <div class="form-text text-danger">@_emailValidationMessage</div>
                        }
                    </div>

                    <div class="mb-3">
                        <label class="form-label">Phone <span class="text-danger">*</span></label>
                        <input type="tel" class="form-control" @bind="_phone" />
                    </div>

