@page "/apply"
@rendermode InteractiveServer
@using sv_de41e81c5e754cf7bf289f3baf4735af.Models
@using sv_de41e81c5e754cf7bf289f3baf4735af.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @* ───── Step Indicator Bar ───── *@
    <nav class="d-flex justify-content-between mb-4 position-relative">
        @for (int i = 0; i < _stepLabels.Length; i++)
        {
            var step = i + 1;
            var label = _stepLabels[i];
            var isCompleted = step < _currentStep;
            var isCurrent = step == _currentStep;
            var isFuture = step > _currentStep;

            <button type="button"
                    class="btn btn-link text-decoration-none text-center p-0 flex-fill @(isFuture && !_submitted ? "text-muted" : "")"
                    style="font-size: 0.85rem; border: none; background: none;"
                    disabled="@(isFuture || _submitted)"
                    @onclick="() => GoToStep(step)">
                <div class="mx-auto mb-1 rounded-circle d-flex align-items-center justify-content-center
                    @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")"
                     style="width: 36px; height: 36px;">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@step</span>
                    }
                </div>
                <span class="@(isCurrent ? "fw-bold text-primary" : "")">@label</span>
            </button>
        }
    </nav>

    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="alert alert-danger">@_errorMessage</div>
    }

    @if (_submitted)
    {
        @* ───── Confirmation ───── *@
        <div class="text-center py-5">
            <div class="mb-3" style="font-size: 3rem; color: green;">&#10003;</div>
            <h3>Application Submitted!</h3>
            <p class="text-muted">Your application has been received.</p>
            <p class="fs-5">Application ID: <strong>@_applicationId</strong></p>
        </div>
    }
    else
    {
        @* ───── Step 1: Personal Info ───── *@
        @if (_currentStep == 1)
        {
            <div class="card">
                <div class="card-body">
                    <h4 class="card-title mb-3">Personal Information</h4>

                    <div class="mb-3">
                        <label class="form-label">Full Name <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" @bind="_fullName" />
                    </div>

                    <div class="mb-3">
                        <label class="form-label">Email <span class="text-danger">*</span></label>
                        <input type="email" class="form-control" @bind="_email" />
                        @if (_emailValidationMessage is not null)
                        {
                            <div class="form-text text-danger">@_emailValidationMessage</div>
                        }
                    </div>

                    <div class="mb-3">
                        <label class="form-label">Phone <span class="text-danger">*</span></label>
                        <input type="tel" class="form-control" @bind="_phone" />
                    </div>

                    <div class="mb-3">
                        <label class="form-label">Address <span class="text-danger">*</span></label>
                        <textarea class="form-control" rows="2" @bind="_address"></textarea>
                    </div>

                    <div class="d-flex justify-content-end">
                        <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@_isValidating">
                            @if (_isValidating)
                            {
                                <span class="spinner-border spinner-border-sm me-1"></span>
                            }
                            Next
                        </button>
                    </div>
                </div>
            </div>
        }

        @* ───── Step 2: Work History ───── *@
        @if (_currentStep == 2)
        {
            <div class="card">
                <div class="card-body">
                    <h4 class="card-title mb-3">Work History</h4>

                    @for (int i = 0; i < _workEntries.Count; i++)
                    {
                        var index = i;
                        var entry = _workEntries[index];

                        <div class="border rounded p-3 mb-3">
                            <div class="d-flex justify-content-between align-items-center mb-2">
                                <h6 class="mb-0">Position @(index + 1)</h6>
                                @if (_workEntries.Count > 1)
                                {
                                    <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => RemoveWorkEntry(index)">Remove</button>
                                }
                            </div>

                            <div class="row mb-2">
                                <div class="col-md-6">
                                    <label class="form-label">Company <span class="text-danger">*</span></label>
                                    <input type="text" class="form-control" value="@entry.Company"
                                           @onchange="(e) => UpdateWorkEntry(index, entry with { Company = e.Value?.ToString() ?? string.Empty })" />
                                </div>
                                <div class="col-md-6">
                                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                                    <input type="text" class="form-control" value="@entry.Title"
                                           @onchange="(e) => UpdateWorkEntry(index, entry with { Title = e.Value?.ToString() ?? string.Empty })" />
                                </div>
                            </div>

                            <div class="row mb-2">
                                <div class="col-md-4">
                                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                                    <input type="date" class="form-control" value="@FormatDate(entry.StartDate)"
                                           @onchange="(e) => UpdateWorkEntry(index, entry with { StartDate = ParseDate(e.Value) })" />
                                </div>
                                <div class="col-md-4">
                                    <label class="form-label">End Date</label>
                                    <input type="date" class="form-control" value="@FormatDate(entry.EndDate)"
                                           disabled="@entry.IsCurrent"
                                           @onchange="(e) => UpdateWorkEntry(index, entry with { EndDate = ParseNullableDate(e.Value) })" />
                                </div>
                                <div class="col-md-4 d-flex align-items-end mb-1">
                                    <div class="form-check">
                                        <input type="checkbox" class="form-check-input" id="current-@index" checked="@entry.IsCurrent"
                                               @onchange="(e) => UpdateWorkEntry(index, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = (bool)(e.Value ?? false) ? null : entry.EndDate })" />
                                        <label class="form-check-label" for="current-@index">Currently working here</label>
                                    </div>
                                </div>
                            </div>

                            <div class="mb-0">
                                <label class="form-label">Description</label>
                                <textarea class="form-control" rows="2" value="@entry.Description"
                                          @onchange="(e) => UpdateWorkEntry(index, entry with { Description = e.Value?.ToString() ?? string.Empty })"></textarea>
                            </div>
                        </div>
                    }

                    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">
                        + Add Another Position
                    </button>

                    <div class="d-flex justify-content-between">
                        <button class="btn btn-secondary" @onclick="() => GoToStep(1)">Back</button>
                        <button class="btn btn-primary" @onclick="NextFromWorkHistory">Next</button>
                    </div>
                </div>
            </div>
        }

        @* ───── Step 3: References ───── *@
        @if (_currentStep == 3)
        {
            <div class="card">
                <div class="card-body">
                    <h4 class="card-title mb-3">References</h4>

                    @for (int i = 0; i < _references.Count; i++)
                    {
                        var index = i;
                        var reference = _references[index];

                        <div class="border rounded p-3 mb-3">
                            <div class="d-flex justify-content-between align-items-center mb-2">
                                <h6 class="mb-0">Reference @(index + 1)</h6>
                                @if (_references.Count > 2)
                                {
                                    <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                                }
                            </div>

                            <div class="row mb-2">
                                <div class="col-md-6">
                                    <label class="form-label">Name <span class="text-danger">*</span></label>
                                    <input type="text" class="form-control" value="@reference.Name"
                                           @onchange="(e) => UpdateReference(index, reference with { Name = e.Value?.ToString() ?? string.Empty })" />
                                </div>
                                <div class="col-md-6">
                                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                                    <input type="text" class="form-control" value="@reference.Relationship"
                                           @onchange="(e) => UpdateReference(index, reference with { Relationship = e.Value?.ToString() ?? string.Empty })" />
                                </div>
                            </div>

                            <div class="row">
                                <div class="col-md-6">
                                    <label class="form-label">Email <span class="text-danger">*</span></label>
                                    <input type="email" class="form-control" value="@reference.Email"
                                           @onchange="(e) => UpdateReference(index, reference with { Email = e.Value?.ToString() ?? string.Empty })" />
                                </div>
                                <div class="col-md-6">
                                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                                    <input type="tel" class="form-control" value="@reference.Phone"
                                           @onchange="(e) => UpdateReference(index, reference with { Phone = e.Value?.ToString() ?? string.Empty })" />
                                </div>
                            </div>
                        </div>
                    }

                    @if (_references.Count < 3)
                    {
                        <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
                            + Add Reference
                        </button>
                    }

                    <div class="d-flex justify-content-between">
                        <button class="btn btn-secondary" @onclick="() => GoToStep(2)">Back</button>
                        <button class="btn btn-primary" @onclick="NextFromReferences">Next</button>
                    </div>
                </div>
            </div>
        }

        @* ───── Step 4: Cover Letter ───── *@
        @if (_currentStep == 4)
        {
            <div class="card">
                <div class="card-body">
                    <h4 class="card-title mb-3">Cover Letter</h4>

                    <div class="mb-2">
                        <textarea class="form-control" rows="10" maxlength="2000"
                                  @bind="_coverLetter" @bind:event="oninput"></textarea>
                    </div>
                    <div class="form-text text-end mb-3">@(_coverLetter?.Length ?? 0) / 2000 characters</div>

                    <div class="d-flex justify-content-between">
                        <button class="btn btn-secondary" @onclick="() => GoToStep(3)">Back</button>
                        <button class="btn btn-primary" @onclick="() => GoToStep(5)">Next</button>
                    </div>
                </div>
            </div>
        }

        @* ───── Step 5: Review & Submit ───── *@
        @if (_currentStep == 5)
        {
            <div class="card">
                <div class="card-body">
                    <h4 class="card-title mb-4">Review & Submit</h4>

                    @* Personal Info *@
                    <div class="mb-4">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h5 class="mb-0">Personal Information</h5>
                            <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(1)">Edit</button>
                        </div>
                        <dl class="row mb-0">
                            <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@_fullName</dd>
                            <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@_email</dd>
                            <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@_phone</dd>
                            <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@_address</dd>
                        </dl>
                    </div>
                    <hr />

                    @* Work History *@
                    <div class="mb-4">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h5 class="mb-0">Work History</h5>
                            <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(2)">Edit</button>
                        </div>
                        @foreach (var entry in _workEntries)
                        {
                            <div class="mb-2 ps-2 border-start border-3">
                                <strong>@entry.Title</strong> at @entry.Company<br />
                                <small class="text-muted">
                                    @entry.StartDate.ToString("MMM yyyy") &ndash;
                                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                                </small>
                                @if (!string.IsNullOrWhiteSpace(entry.Description))
                                {
                                    <p class="mb-0 mt-1">@entry.Description</p>
                                }
                            </div>
                        }
                    </div>
                    <hr />

                    @* References *@
                    <div class="mb-4">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h5 class="mb-0">References</h5>
                            <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(3)">Edit</button>
                        </div>
                        @foreach (var r in _references)
                        {
                            <div class="mb-2 ps-2 border-start border-3">
                                <strong>@r.Name</strong> &mdash; @r.Relationship<br />
                                <small class="text-muted">@r.Email &middot; @r.Phone</small>
                            </div>
                        }
                    </div>
                    <hr />

                    @* Cover Letter *@
                    <div class="mb-4">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h5 class="mb-0">Cover Letter</h5>
                            <button class="btn btn-link btn-sm p-0" @onclick="() => GoToStep(4)">Edit</button>
                        </div>
                        <p style="white-space: pre-wrap;">@_coverLetter</p>
                    </div>

                    <div class="d-flex justify-content-between">
                        <button class="btn btn-secondary" @onclick="() => GoToStep(4)">Back</button>
                        <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_isSubmitting">
                            @if (_isSubmitting)
                            {
                                <span class="spinner-border spinner-border-sm me-1"></span>
                            }
                            Submit Application
                        </button>
                    </div>
                </div>
            </div>
        }
    }
</div>

